    pub async fn upsert_compatibility_set(
        &self,
        tenant_id: &str,
        queue_kind: TaskQueueKind,
        task_queue: &str,
        set_id: &str,
        build_ids: &[String],
        is_default: bool,
    ) -> Result<CompatibilitySetRecord> {
        let now = Utc::now();
        if is_default {
            sqlx::query(
                r#"
                UPDATE task_queue_compatibility_sets
                SET is_default = FALSE,
                    updated_at = $4
                WHERE tenant_id = $1 AND queue_kind = $2 AND task_queue = $3
                "#,
            )
            .bind(tenant_id)
            .bind(queue_kind.as_str())
            .bind(task_queue)
            .bind(now)
            .execute(&self.pool)
            .await
            .context("failed to clear existing default compatibility set")?;
        }

        sqlx::query(
            r#"
            INSERT INTO task_queue_compatibility_sets (
                tenant_id,
                queue_kind,
                task_queue,
                set_id,
                is_default,
                created_at,
                updated_at
            )
            VALUES ($1, $2, $3, $4, $5, $6, $6)
            ON CONFLICT (tenant_id, queue_kind, task_queue, set_id)
            DO UPDATE SET
                is_default = EXCLUDED.is_default,
                updated_at = EXCLUDED.updated_at
            "#,
        )
        .bind(tenant_id)
        .bind(queue_kind.as_str())
        .bind(task_queue)
        .bind(set_id)
        .bind(is_default)
        .bind(now)
        .execute(&self.pool)
        .await
        .context("failed to upsert compatibility set")?;

        sqlx::query(
            r#"
            DELETE FROM task_queue_compatibility_set_builds
            WHERE tenant_id = $1 AND queue_kind = $2 AND task_queue = $3 AND set_id = $4
            "#,
        )
        .bind(tenant_id)
        .bind(queue_kind.as_str())
        .bind(task_queue)
        .bind(set_id)
        .execute(&self.pool)
        .await
        .context("failed to clear compatibility set members")?;

        for build_id in build_ids {
            sqlx::query(
                r#"
                INSERT INTO task_queue_compatibility_set_builds (
                    tenant_id,
                    queue_kind,
                    task_queue,
                    set_id,
                    build_id,
                    created_at
                )
                VALUES ($1, $2, $3, $4, $5, $6)
                "#,
            )
            .bind(tenant_id)
            .bind(queue_kind.as_str())
            .bind(task_queue)
            .bind(set_id)
            .bind(build_id)
            .bind(now)
            .execute(&self.pool)
            .await
            .context("failed to upsert compatibility set member")?;
        }

        self.get_compatibility_set(tenant_id, queue_kind, task_queue, set_id)
            .await?
            .context("compatibility set was not found after upsert")
    }

    pub async fn set_default_compatibility_set(
        &self,
        tenant_id: &str,
        queue_kind: TaskQueueKind,
        task_queue: &str,
        set_id: &str,
    ) -> Result<()> {
        let now = Utc::now();
        let mut tx =
            self.pool.begin().await.context("failed to begin default-set promotion transaction")?;
        sqlx::query(
            r#"
            UPDATE task_queue_compatibility_sets
            SET is_default = FALSE,
                updated_at = $4
            WHERE tenant_id = $1 AND queue_kind = $2 AND task_queue = $3
            "#,
        )
        .bind(tenant_id)
        .bind(queue_kind.as_str())
        .bind(task_queue)
        .bind(now)
        .execute(&mut *tx)
        .await
        .context("failed to clear existing default compatibility set")?;
        let updated = sqlx::query(
            r#"
            UPDATE task_queue_compatibility_sets
            SET is_default = TRUE,
                updated_at = $5
            WHERE tenant_id = $1
              AND queue_kind = $2
              AND task_queue = $3
              AND set_id = $4
            "#,
        )
        .bind(tenant_id)
        .bind(queue_kind.as_str())
        .bind(task_queue)
        .bind(set_id)
        .bind(now)
        .execute(&mut *tx)
        .await
        .context("failed to promote default compatibility set")?;
        if updated.rows_affected() != 1 {
            tx.rollback()
                .await
                .context("failed to rollback missing default-set promotion transaction")?;
            anyhow::bail!("compatibility set {set_id} was not found for task queue {task_queue}");
        }
        tx.commit().await.context("failed to commit default-set promotion transaction")?;

        Ok(())
    }

    pub async fn get_compatibility_set(
        &self,
        tenant_id: &str,
        queue_kind: TaskQueueKind,
        task_queue: &str,
        set_id: &str,
    ) -> Result<Option<CompatibilitySetRecord>> {
        let row = sqlx::query(
            r#"
            SELECT tenant_id, queue_kind, task_queue, set_id, is_default, created_at, updated_at
            FROM task_queue_compatibility_sets
            WHERE tenant_id = $1
              AND queue_kind = $2
              AND task_queue = $3
              AND set_id = $4
            "#,
        )
        .bind(tenant_id)
        .bind(queue_kind.as_str())
        .bind(task_queue)
        .bind(set_id)
        .fetch_optional(&self.pool)
        .await
        .context("failed to load compatibility set")?;

        match row {
            Some(row) => {
                let build_ids = self
                    .list_compatibility_set_build_ids(
                        tenant_id,
                        queue_kind.clone(),
                        task_queue,
                        set_id,
                    )
                    .await?;
                Ok(Some(Self::decode_compatibility_set_row(row, build_ids)?))
            }
            None => Ok(None),
        }
    }

    pub async fn list_compatibility_sets(
        &self,
        tenant_id: &str,
        queue_kind: TaskQueueKind,
        task_queue: &str,
    ) -> Result<Vec<CompatibilitySetRecord>> {
        let rows = sqlx::query(
            r#"
            SELECT tenant_id, queue_kind, task_queue, set_id, is_default, created_at, updated_at
            FROM task_queue_compatibility_sets
            WHERE tenant_id = $1 AND queue_kind = $2 AND task_queue = $3
            ORDER BY set_id ASC
            "#,
        )
        .bind(tenant_id)
        .bind(queue_kind.as_str())
        .bind(task_queue)
        .fetch_all(&self.pool)
        .await
        .context("failed to list compatibility sets")?;

        let mut sets = Vec::with_capacity(rows.len());
        for row in rows {
            let set_id: String =
                row.try_get("set_id").context("compatibility set set_id missing")?;
            let build_ids = self
                .list_compatibility_set_build_ids(
                    tenant_id,
                    queue_kind.clone(),
                    task_queue,
                    &set_id,
                )
                .await?;
            sets.push(Self::decode_compatibility_set_row(row, build_ids)?);
        }
        Ok(sets)
    }

    pub async fn list_default_compatible_build_ids(
        &self,
        tenant_id: &str,
        queue_kind: TaskQueueKind,
        task_queue: &str,
    ) -> Result<Vec<String>> {
        let row = sqlx::query(
            r#"
            SELECT set_id
            FROM task_queue_compatibility_sets
            WHERE tenant_id = $1 AND queue_kind = $2 AND task_queue = $3 AND is_default = TRUE
            LIMIT 1
            "#,
        )
        .bind(tenant_id)
        .bind(queue_kind.as_str())
        .bind(task_queue)
        .fetch_optional(&self.pool)
        .await
        .context("failed to load default compatibility set")?;

        if let Some(row) = row {
            let set_id: String = row.try_get("set_id").context("default set_id missing")?;
            return self
                .list_compatibility_set_build_ids(tenant_id, queue_kind, task_queue, &set_id)
                .await;
        }

        Ok(self
            .list_task_queue_builds(tenant_id, queue_kind, task_queue)
            .await?
            .into_iter()
            .map(|record| record.build_id)
            .collect())
    }

    pub async fn is_build_compatible_with_queue(
        &self,
        tenant_id: &str,
        queue_kind: TaskQueueKind,
        task_queue: &str,
        build_id: &str,
    ) -> Result<bool> {
        let registered_builds =
            self.list_task_queue_builds(tenant_id, queue_kind.clone(), task_queue).await?;
        if registered_builds.is_empty() {
            return Ok(true);
        }
        let compatible =
            self.list_default_compatible_build_ids(tenant_id, queue_kind, task_queue).await?;
        Ok(compatible.is_empty() || compatible.iter().any(|candidate| candidate == build_id))
    }

    pub async fn workflow_build_supports_artifact(
        &self,
        tenant_id: &str,
        task_queue: &str,
        build_id: &str,
        artifact_hash: Option<&str>,
    ) -> Result<bool> {
        let Some(record) = self
            .get_task_queue_build(tenant_id, TaskQueueKind::Workflow, task_queue, build_id)
            .await?
        else {
            return Ok(true);
        };
        let Some(artifact_hash) = artifact_hash else {
            return Ok(true);
        };
        Ok(record.artifact_hashes.is_empty()
            || record.artifact_hashes.iter().any(|candidate| candidate == artifact_hash))
    }

    pub async fn infer_workflow_task_queue_for_artifact(
        &self,
        tenant_id: &str,
        artifact_hash: &str,
    ) -> Result<Option<String>> {
        let row = sqlx::query(
            r#"
            SELECT builds.task_queue
            FROM task_queue_builds builds
            LEFT JOIN task_queue_compatibility_sets sets
              ON sets.tenant_id = builds.tenant_id
             AND sets.queue_kind = builds.queue_kind
             AND sets.task_queue = builds.task_queue
             AND sets.is_default = TRUE
            WHERE builds.tenant_id = $1
              AND builds.queue_kind = 'workflow'
              AND builds.artifact_hashes ? $2
            ORDER BY
              CASE WHEN sets.set_id IS NULL THEN 1 ELSE 0 END ASC,
              builds.updated_at DESC,
              builds.task_queue ASC
            LIMIT 1
            "#,
        )
        .bind(tenant_id)
        .bind(artifact_hash)
        .fetch_optional(&self.pool)
        .await
        .context("failed to infer workflow task queue for artifact")?;

        row.map(|row| row.try_get("task_queue").context("inferred workflow task_queue missing"))
            .transpose()
    }

    pub async fn get_default_workflow_artifact_for_queue(
        &self,
        tenant_id: &str,
        task_queue: &str,
        workflow_id: &str,
    ) -> Result<Option<CompiledWorkflowArtifact>> {
        let build_ids = self
            .list_default_compatible_build_ids(tenant_id, TaskQueueKind::Workflow, task_queue)
            .await?;
        if build_ids.is_empty() {
            return Ok(None);
        }

        let mut selected = None;
        for build_id in build_ids {
            let Some(build) = self
                .get_task_queue_build(tenant_id, TaskQueueKind::Workflow, task_queue, &build_id)
                .await?
            else {
                continue;
            };
            for artifact_hash in build.artifact_hashes {
                let Some(candidate) =
                    self.get_artifact_by_hash(tenant_id, workflow_id, &artifact_hash).await?
                else {
                    continue;
                };
                let replace = selected
                    .as_ref()
                    .map(|current: &CompiledWorkflowArtifact| {
                        candidate.definition_version > current.definition_version
                    })
                    .unwrap_or(true);
                if replace {
                    selected = Some(candidate);
                }
            }
        }

        Ok(selected)
    }

    pub async fn upsert_queue_poller(
        &self,
        tenant_id: &str,
        queue_kind: TaskQueueKind,
        task_queue: &str,
        poller_id: &str,
        build_id: &str,
        partition_id: Option<i32>,
        metadata: Option<&Value>,
        ttl: chrono::Duration,
    ) -> Result<QueuePollerRecord> {
        let now = Utc::now();
        let expires_at = now + ttl;
        sqlx::query(
            r#"
            INSERT INTO task_queue_pollers (
                tenant_id,
                queue_kind,
                task_queue,
                poller_id,
                build_id,
                partition_id,
                metadata,
                last_seen_at,
                expires_at,
                created_at,
                updated_at
            )
            VALUES ($1, $2, $3, $4, $5, $6, $7, $8, $9, $8, $8)
            ON CONFLICT (tenant_id, queue_kind, task_queue, poller_id)
            DO UPDATE SET
                build_id = EXCLUDED.build_id,
                partition_id = EXCLUDED.partition_id,
                metadata = EXCLUDED.metadata,
                last_seen_at = EXCLUDED.last_seen_at,
                expires_at = EXCLUDED.expires_at,
                updated_at = EXCLUDED.updated_at
            "#,
        )
        .bind(tenant_id)
        .bind(queue_kind.as_str())
        .bind(task_queue)
        .bind(poller_id)
        .bind(build_id)
        .bind(partition_id)
        .bind(metadata.cloned().map(Json))
        .bind(now)
        .bind(expires_at)
        .execute(&self.pool)
        .await
        .context("failed to upsert task queue poller")?;

        self.get_queue_poller(tenant_id, queue_kind, task_queue, poller_id)
            .await?
            .context("task queue poller was not found after upsert")
    }

