    pub async fn delete_topic_adapter(&self, tenant_id: &str, adapter_id: &str) -> Result<bool> {
        let mut tx =
            self.pool.begin().await.context("failed to begin topic adapter delete transaction")?;

        sqlx::query(
            r#"
            DELETE FROM topic_adapter_dead_letters
            WHERE tenant_id = $1 AND adapter_id = $2
            "#,
        )
        .bind(tenant_id)
        .bind(adapter_id)
        .execute(&mut *tx)
        .await
        .context("failed to delete topic adapter dead letters")?;

        sqlx::query(
            r#"
            DELETE FROM topic_adapter_offsets
            WHERE tenant_id = $1 AND adapter_id = $2
            "#,
        )
        .bind(tenant_id)
        .bind(adapter_id)
        .execute(&mut *tx)
        .await
        .context("failed to delete topic adapter offsets")?;

        sqlx::query(
            r#"
            DELETE FROM topic_adapter_ownership
            WHERE tenant_id = $1 AND adapter_id = $2
            "#,
        )
        .bind(tenant_id)
        .bind(adapter_id)
        .execute(&mut *tx)
        .await
        .context("failed to delete topic adapter ownership")?;

        let result = sqlx::query(
            r#"
            DELETE FROM topic_adapters
            WHERE tenant_id = $1 AND adapter_id = $2
            "#,
        )
        .bind(tenant_id)
        .bind(adapter_id)
        .execute(&mut *tx)
        .await
        .context("failed to delete topic adapter")?;

        tx.commit().await.context("failed to commit topic adapter delete transaction")?;
        Ok(result.rows_affected() > 0)
    }

    pub async fn claim_topic_adapter_ownership(
        &self,
        tenant_id: &str,
        adapter_id: &str,
        owner_id: &str,
        lease_ttl: std::time::Duration,
    ) -> Result<Option<TopicAdapterOwnershipRecord>> {
        let mut tx = self
            .pool
            .begin()
            .await
            .context("failed to begin topic adapter ownership transaction")?;
        let now = Utc::now();
        let lease_expires_at = now
            + chrono::Duration::from_std(lease_ttl)
                .context("topic adapter ownership lease ttl overflow")?;
        let row = sqlx::query(
            r#"
            SELECT
                tenant_id,
                adapter_id,
                owner_id,
                owner_epoch,
                lease_expires_at,
                acquired_at,
                last_transition_at,
                updated_at
            FROM topic_adapter_ownership
            WHERE tenant_id = $1 AND adapter_id = $2
            FOR UPDATE
            "#,
        )
        .bind(tenant_id)
        .bind(adapter_id)
        .fetch_optional(&mut *tx)
        .await
        .context("failed to load topic adapter ownership for claim")?;

        let ownership = match row {
            Some(row) => {
                let current = Self::decode_topic_adapter_ownership_row(row)?;
                if current.owner_id == owner_id {
                    sqlx::query(
                        r#"
                        UPDATE topic_adapter_ownership
                        SET lease_expires_at = $4,
                            updated_at = $5
                        WHERE tenant_id = $1 AND adapter_id = $2 AND owner_id = $3
                        "#,
                    )
                    .bind(tenant_id)
                    .bind(adapter_id)
                    .bind(owner_id)
                    .bind(lease_expires_at)
                    .bind(now)
                    .execute(&mut *tx)
                    .await
                    .context("failed to renew existing topic adapter ownership claim")?;
                    TopicAdapterOwnershipRecord { lease_expires_at, updated_at: now, ..current }
                } else if current.lease_expires_at <= now {
                    let next_epoch = current.owner_epoch + 1;
                    let takeover_latency_ms = now
                        .signed_duration_since(current.lease_expires_at)
                        .num_milliseconds()
                        .max(0);
                    sqlx::query(
                        r#"
                        UPDATE topic_adapter_ownership
                        SET owner_id = $3,
                            owner_epoch = $4,
                            lease_expires_at = $5,
                            acquired_at = $6,
                            last_transition_at = $6,
                            updated_at = $6
                        WHERE tenant_id = $1 AND adapter_id = $2
                        "#,
                    )
                    .bind(tenant_id)
                    .bind(adapter_id)
                    .bind(owner_id)
                    .bind(
                        i64::try_from(next_epoch)
                            .context("topic adapter ownership epoch exceeds i64")?,
                    )
                    .bind(lease_expires_at)
                    .bind(now)
                    .execute(&mut *tx)
                    .await
                    .context("failed to transfer expired topic adapter ownership")?;
                    sqlx::query(
                        r#"
                        UPDATE topic_adapters
                        SET ownership_handoff_count = ownership_handoff_count + 1,
                            last_handoff_at = $3,
                            last_takeover_latency_ms = $4,
                            updated_at = $3
                        WHERE tenant_id = $1 AND adapter_id = $2
                        "#,
                    )
                    .bind(tenant_id)
                    .bind(adapter_id)
                    .bind(now)
                    .bind(takeover_latency_ms)
                    .execute(&mut *tx)
                    .await
                    .context("failed to update topic adapter handoff metrics")?;
                    TopicAdapterOwnershipRecord {
                        tenant_id: tenant_id.to_owned(),
                        adapter_id: adapter_id.to_owned(),
                        owner_id: owner_id.to_owned(),
                        owner_epoch: next_epoch,
                        lease_expires_at,
                        acquired_at: now,
                        last_transition_at: now,
                        updated_at: now,
                    }
                } else {
                    tx.commit()
                        .await
                        .context("failed to commit busy topic adapter ownership transaction")?;
                    return Ok(None);
                }
            }
            None => {
                sqlx::query(
                    r#"
                    INSERT INTO topic_adapter_ownership (
                        tenant_id,
                        adapter_id,
                        owner_id,
                        owner_epoch,
                        lease_expires_at,
                        acquired_at,
                        last_transition_at,
                        updated_at
                    )
                    VALUES ($1, $2, $3, $4, $5, $6, $6, $6)
                    "#,
                )
                .bind(tenant_id)
                .bind(adapter_id)
                .bind(owner_id)
                .bind(1_i64)
                .bind(lease_expires_at)
                .bind(now)
                .execute(&mut *tx)
                .await
                .context("failed to insert topic adapter ownership record")?;
                TopicAdapterOwnershipRecord {
                    tenant_id: tenant_id.to_owned(),
                    adapter_id: adapter_id.to_owned(),
                    owner_id: owner_id.to_owned(),
                    owner_epoch: 1,
                    lease_expires_at,
                    acquired_at: now,
                    last_transition_at: now,
                    updated_at: now,
                }
            }
        };

        tx.commit().await.context("failed to commit topic adapter ownership claim transaction")?;
        Ok(Some(ownership))
    }

    pub async fn renew_topic_adapter_ownership(
        &self,
        tenant_id: &str,
        adapter_id: &str,
        owner_id: &str,
        owner_epoch: u64,
        lease_ttl: std::time::Duration,
    ) -> Result<Option<TopicAdapterOwnershipRecord>> {
        let now = Utc::now();
        let lease_expires_at = now
            + chrono::Duration::from_std(lease_ttl)
                .context("topic adapter ownership lease ttl overflow")?;
        let result = sqlx::query(
            r#"
            UPDATE topic_adapter_ownership
            SET lease_expires_at = $5,
                updated_at = $6
            WHERE tenant_id = $1
              AND adapter_id = $2
              AND owner_id = $3
              AND owner_epoch = $4
              AND lease_expires_at > $6
            "#,
        )
        .bind(tenant_id)
        .bind(adapter_id)
        .bind(owner_id)
        .bind(i64::try_from(owner_epoch).context("topic adapter ownership epoch exceeds i64")?)
        .bind(lease_expires_at)
        .bind(now)
        .execute(&self.pool)
        .await
        .context("failed to renew topic adapter ownership")?;

        if result.rows_affected() == 0 {
            return Ok(None);
        }

        self.get_topic_adapter_ownership(tenant_id, adapter_id).await
    }

