    pub async fn record_topic_adapter_success(
        &self,
        tenant_id: &str,
        adapter_id: &str,
        partition_id: i32,
        log_offset: i64,
        processed_at: DateTime<Utc>,
    ) -> Result<()> {
        let mut tx =
            self.pool.begin().await.context("failed to begin topic adapter success transaction")?;
        if self
            .prepare_topic_adapter_offset_commit(
                &mut tx,
                tenant_id,
                adapter_id,
                partition_id,
                log_offset,
                None,
            )
            .await?
        {
            self.apply_topic_adapter_success_commit(
                &mut tx,
                tenant_id,
                adapter_id,
                partition_id,
                log_offset,
                processed_at,
            )
            .await?;
        }
        tx.commit().await.context("failed to commit topic adapter success transaction")?;
        Ok(())
    }

    pub async fn record_topic_adapter_success_if_owned(
        &self,
        tenant_id: &str,
        adapter_id: &str,
        partition_id: i32,
        log_offset: i64,
        processed_at: DateTime<Utc>,
        owner_id: &str,
        owner_epoch: u64,
    ) -> Result<bool> {
        let mut tx = self
            .pool
            .begin()
            .await
            .context("failed to begin owned topic adapter success transaction")?;
        if !self
            .prepare_topic_adapter_offset_commit(
                &mut tx,
                tenant_id,
                adapter_id,
                partition_id,
                log_offset,
                Some((owner_id, owner_epoch)),
            )
            .await?
        {
            tx.commit()
                .await
                .context("failed to commit rejected topic adapter success transaction")?;
            return Ok(false);
        }
        self.apply_topic_adapter_success_commit(
            &mut tx,
            tenant_id,
            adapter_id,
            partition_id,
            log_offset,
            processed_at,
        )
        .await?;
        tx.commit().await.context("failed to commit owned topic adapter success transaction")?;
        Ok(true)
    }

