    async fn prepare_topic_adapter_offset_commit(
        &self,
        tx: &mut sqlx::Transaction<'_, Postgres>,
        tenant_id: &str,
        adapter_id: &str,
        partition_id: i32,
        log_offset: i64,
        ownership: Option<(&str, u64)>,
    ) -> Result<bool> {
        if let Some((owner_id, owner_epoch)) = ownership {
            let now = Utc::now();
            let owner_row = sqlx::query(
                r#"
                SELECT 1
                FROM topic_adapter_ownership
                WHERE tenant_id = $1
                  AND adapter_id = $2
                  AND owner_id = $3
                  AND owner_epoch = $4
                  AND lease_expires_at > $5
                FOR UPDATE
                "#,
            )
            .bind(tenant_id)
            .bind(adapter_id)
            .bind(owner_id)
            .bind(i64::try_from(owner_epoch).context("topic adapter ownership epoch exceeds i64")?)
            .bind(now)
            .fetch_optional(&mut **tx)
            .await
            .context("failed to validate topic adapter ownership for offset commit")?;
            if owner_row.is_none() {
                return Ok(false);
            }
        }

        let current_offset = sqlx::query_scalar::<_, i64>(
            r#"
            SELECT log_offset
            FROM topic_adapter_offsets
            WHERE tenant_id = $1 AND adapter_id = $2 AND partition_id = $3
            FOR UPDATE
            "#,
        )
        .bind(tenant_id)
        .bind(adapter_id)
        .bind(partition_id)
        .fetch_optional(&mut **tx)
        .await
        .context("failed to load topic adapter offset for commit")?;

        Ok(current_offset.is_none_or(|existing| existing < log_offset))
    }

    async fn apply_topic_adapter_success_commit(
        &self,
        tx: &mut sqlx::Transaction<'_, Postgres>,
        tenant_id: &str,
        adapter_id: &str,
        partition_id: i32,
        log_offset: i64,
        processed_at: DateTime<Utc>,
    ) -> Result<()> {
        sqlx::query(
            r#"
            INSERT INTO topic_adapter_offsets (
                tenant_id,
                adapter_id,
                partition_id,
                log_offset,
                updated_at
            )
            VALUES ($1, $2, $3, $4, $5)
            ON CONFLICT (tenant_id, adapter_id, partition_id)
            DO UPDATE SET
                log_offset = EXCLUDED.log_offset,
                updated_at = EXCLUDED.updated_at
            "#,
        )
        .bind(tenant_id)
        .bind(adapter_id)
        .bind(partition_id)
        .bind(log_offset)
        .bind(processed_at)
        .execute(&mut **tx)
        .await
        .context("failed to commit topic adapter offset")?;

        sqlx::query(
            r#"
            UPDATE topic_adapters
            SET processed_count = processed_count + 1,
                last_processed_at = $3,
                last_error = NULL,
                last_error_at = NULL,
                updated_at = $3
            WHERE tenant_id = $1 AND adapter_id = $2
            "#,
        )
        .bind(tenant_id)
        .bind(adapter_id)
        .bind(processed_at)
        .execute(&mut **tx)
        .await
        .context("failed to update topic adapter success metrics")?;

        Ok(())
    }

    async fn apply_topic_adapter_dead_letter_commit(
        &self,
        tx: &mut sqlx::Transaction<'_, Postgres>,
        tenant_id: &str,
        adapter_id: &str,
        partition_id: i32,
        log_offset: i64,
        record_key: Option<&str>,
        payload: &Value,
        error: &str,
        occurred_at: DateTime<Utc>,
    ) -> Result<()> {
        sqlx::query(
            r#"
            INSERT INTO topic_adapter_dead_letters (
                tenant_id,
                adapter_id,
                partition_id,
                log_offset,
                record_key,
                payload,
                error,
                replay_count,
                last_replay_at,
                last_replay_error,
                resolved_at,
                occurred_at,
                updated_at
            )
            VALUES ($1, $2, $3, $4, $5, $6, $7, 0, NULL, NULL, NULL, $8, $8)
            ON CONFLICT (tenant_id, adapter_id, partition_id, log_offset)
            DO UPDATE SET
                record_key = EXCLUDED.record_key,
                payload = EXCLUDED.payload,
                error = EXCLUDED.error,
                replay_count = 0,
                last_replay_at = NULL,
                last_replay_error = NULL,
                resolved_at = NULL,
                occurred_at = EXCLUDED.occurred_at,
                updated_at = EXCLUDED.updated_at
            "#,
        )
        .bind(tenant_id)
        .bind(adapter_id)
        .bind(partition_id)
        .bind(log_offset)
        .bind(record_key)
        .bind(Json(payload))
        .bind(error)
        .bind(occurred_at)
        .execute(&mut **tx)
        .await
        .context("failed to upsert topic adapter dead letter")?;

        sqlx::query(
            r#"
            INSERT INTO topic_adapter_offsets (
                tenant_id,
                adapter_id,
                partition_id,
                log_offset,
                updated_at
            )
            VALUES ($1, $2, $3, $4, $5)
            ON CONFLICT (tenant_id, adapter_id, partition_id)
            DO UPDATE SET
                log_offset = EXCLUDED.log_offset,
                updated_at = EXCLUDED.updated_at
            "#,
        )
        .bind(tenant_id)
        .bind(adapter_id)
        .bind(partition_id)
        .bind(log_offset)
        .bind(occurred_at)
        .execute(&mut **tx)
        .await
        .context("failed to commit topic adapter dead letter offset")?;

        sqlx::query(
            r#"
            UPDATE topic_adapters
            SET failed_count = failed_count + 1,
                last_error = $3,
                last_error_at = $4,
                updated_at = $4
            WHERE tenant_id = $1 AND adapter_id = $2
            "#,
        )
        .bind(tenant_id)
        .bind(adapter_id)
        .bind(error)
        .bind(occurred_at)
        .execute(&mut **tx)
        .await
        .context("failed to update topic adapter dead letter metrics")?;

        Ok(())
    }

    pub async fn record_topic_adapter_dead_letter_replay_result(
        &self,
        tenant_id: &str,
        adapter_id: &str,
        partition_id: i32,
        log_offset: i64,
        replayed_at: DateTime<Utc>,
        replay_error: Option<&str>,
        resolved: bool,
    ) -> Result<Option<TopicAdapterDeadLetterRecord>> {
        let row = sqlx::query(
            r#"
            UPDATE topic_adapter_dead_letters
            SET replay_count = replay_count + 1,
                last_replay_at = $5,
                last_replay_error = $6,
                resolved_at = CASE WHEN $7 THEN $5 ELSE NULL END,
                updated_at = $5
            WHERE tenant_id = $1
              AND adapter_id = $2
              AND partition_id = $3
              AND log_offset = $4
            RETURNING
                tenant_id,
                adapter_id,
                partition_id,
                log_offset,
                record_key,
                payload,
                error,
                replay_count,
                last_replay_at,
                last_replay_error,
                resolved_at,
                occurred_at,
                updated_at
            "#,
        )
        .bind(tenant_id)
        .bind(adapter_id)
        .bind(partition_id)
        .bind(log_offset)
        .bind(replayed_at)
        .bind(replay_error)
        .bind(resolved)
        .fetch_optional(&self.pool)
        .await
        .context("failed to record topic adapter dead letter replay result")?;

        row.map(Self::decode_topic_adapter_dead_letter_row).transpose()
    }

