    pub async fn lease_next_workflow_task(
        &self,
        partition_id: i32,
        poller_id: &str,
        build_id: &str,
        lease_ttl: chrono::Duration,
    ) -> Result<Option<WorkflowTaskRecord>> {
        let now = Utc::now();
        let rows = sqlx::query(
            r#"
            SELECT
                task_id,
                tenant_id,
                workflow_instance_id,
                run_id,
                workflow_id,
                definition_version,
                artifact_hash,
                partition_id,
                task_queue,
                preferred_build_id,
                status,
                source_event_id,
                source_event_type,
                source_event,
                mailbox_consumed_seq,
                resume_consumed_seq,
                mailbox_high_watermark,
                resume_high_watermark,
                mailbox_backlog,
                resume_backlog,
                lease_poller_id,
                lease_build_id,
                lease_expires_at,
                attempt_count,
                last_error,
                created_at,
                updated_at
            FROM workflow_tasks
            WHERE partition_id = $1
              AND (mailbox_backlog > 0 OR resume_backlog > 0)
              AND (status = 'pending' OR (status = 'leased' AND lease_expires_at <= $2))
            ORDER BY
                attempt_count ASC,
                CASE WHEN preferred_build_id = $3 THEN 0 ELSE 1 END,
                created_at ASC
            LIMIT 128
            "#,
        )
        .bind(partition_id)
        .bind(now)
        .bind(build_id)
        .fetch_all(&self.pool)
        .await
        .context("failed to list leaseable workflow tasks")?;

        for row in rows {
            let record = Self::decode_workflow_task_row(row)?;
            if !self
                .is_build_compatible_with_queue(
                    &record.tenant_id,
                    TaskQueueKind::Workflow,
                    &record.task_queue,
                    build_id,
                )
                .await?
            {
                continue;
            }
            if !self
                .workflow_build_supports_artifact(
                    &record.tenant_id,
                    &record.task_queue,
                    build_id,
                    record.artifact_hash.as_deref(),
                )
                .await?
            {
                continue;
            }

            let lease_expires_at = now + lease_ttl;
            let updated = sqlx::query(
                r#"
                UPDATE workflow_tasks
                SET status = 'leased',
                    lease_poller_id = $2,
                    lease_build_id = $3,
                    lease_expires_at = $4,
                    updated_at = $5
                WHERE task_id = $1
                  AND (mailbox_backlog > 0 OR resume_backlog > 0)
                  AND (status = 'pending' OR (status = 'leased' AND lease_expires_at <= $5))
                "#,
            )
            .bind(record.task_id)
            .bind(poller_id)
            .bind(build_id)
            .bind(lease_expires_at)
            .bind(now)
            .execute(&self.pool)
            .await
            .context("failed to lease workflow task")?
            .rows_affected();

            if updated == 0 {
                continue;
            }
            return self.get_workflow_task(record.task_id).await;
        }

        Ok(None)
    }

    pub async fn complete_workflow_task(
        &self,
        task_id: Uuid,
        poller_id: &str,
        build_id: &str,
        completed_at: DateTime<Utc>,
    ) -> Result<bool> {
        let updated = sqlx::query(
            r#"
            UPDATE workflow_tasks
            SET mailbox_backlog = GREATEST(mailbox_high_watermark - mailbox_consumed_seq, 0),
                resume_backlog = GREATEST(resume_high_watermark - resume_consumed_seq, 0),
                status = CASE
                    WHEN mailbox_high_watermark > mailbox_consumed_seq
                      OR resume_high_watermark > resume_consumed_seq THEN 'pending'
                    ELSE 'completed'
                END,
                lease_poller_id = CASE
                    WHEN mailbox_high_watermark > mailbox_consumed_seq
                      OR resume_high_watermark > resume_consumed_seq THEN NULL
                    ELSE $2
                END,
                lease_build_id = CASE
                    WHEN mailbox_high_watermark > mailbox_consumed_seq
                      OR resume_high_watermark > resume_consumed_seq THEN NULL
                    ELSE $3
                END,
                lease_expires_at = NULL,
                updated_at = $4
            WHERE task_id = $1
              AND status = 'leased'
              AND lease_poller_id = $2
              AND lease_build_id = $3
            "#,
        )
        .bind(task_id)
        .bind(poller_id)
        .bind(build_id)
        .bind(completed_at)
        .execute(&self.pool)
        .await
        .context("failed to complete workflow task")?
        .rows_affected();

        Ok(updated > 0)
    }

