    pub async fn upsert_request_dedup(
        &self,
        tenant_id: &str,
        instance_id: Option<&str>,
        operation: &str,
        request_id: &str,
        request_hash: &str,
        response: &Value,
    ) -> Result<RequestDedupRecord> {
        let now = Utc::now();
        sqlx::query(
            r#"
            INSERT INTO workflow_request_dedup (
                tenant_id,
                workflow_instance_id,
                operation,
                request_id,
                request_hash,
                response,
                created_at,
                updated_at
            )
            VALUES ($1, $2, $3, $4, $5, $6, $7, $7)
            ON CONFLICT (tenant_id, workflow_instance_id, operation, request_id)
            DO UPDATE SET
                request_hash = EXCLUDED.request_hash,
                response = EXCLUDED.response,
                updated_at = EXCLUDED.updated_at
            "#,
        )
        .bind(tenant_id)
        .bind(instance_id)
        .bind(operation)
        .bind(request_id)
        .bind(request_hash)
        .bind(Json(response))
        .bind(now)
        .execute(&self.pool)
        .await
        .context("failed to upsert request dedup record")?;

        Ok(RequestDedupRecord {
            tenant_id: tenant_id.to_owned(),
            instance_id: instance_id.map(str::to_owned),
            operation: operation.to_owned(),
            request_id: request_id.to_owned(),
            request_hash: request_hash.to_owned(),
            response: response.clone(),
            created_at: now,
            updated_at: now,
        })
    }

