    pub async fn list_activities_for_run_page(
        &self,
        tenant_id: &str,
        instance_id: &str,
        run_id: &str,
        limit: i64,
        offset: i64,
    ) -> Result<Vec<WorkflowActivityRecord>> {
        let rows = sqlx::query(
            r#"
            SELECT
                tenant_id,
                workflow_instance_id,
                run_id,
                workflow_id,
                workflow_version,
                artifact_hash,
                activity_id,
                attempt,
                activity_type,
                activity_capabilities,
                task_queue,
                state,
                status,
                input,
                config,
                output,
                error,
                cancellation_requested,
                cancellation_reason,
                cancellation_metadata,
                worker_id,
                worker_build_id,
                scheduled_at,
                started_at,
                last_heartbeat_at,
                lease_expires_at,
                completed_at,
                schedule_to_start_timeout_ms,
                schedule_to_close_timeout_ms,
                start_to_close_timeout_ms,
                heartbeat_timeout_ms,
                last_event_id,
                last_event_type,
                updated_at
            FROM workflow_activities
            WHERE tenant_id = $1 AND workflow_instance_id = $2 AND run_id = $3
            ORDER BY scheduled_at ASC, activity_id ASC, attempt ASC
            LIMIT $4 OFFSET $5
            "#,
        )
        .bind(tenant_id)
        .bind(instance_id)
        .bind(run_id)
        .bind(limit)
        .bind(offset)
        .fetch_all(&self.pool)
        .await
        .context("failed to list workflow activities")?;

        rows.into_iter().map(Self::decode_activity_row).collect()
    }

