    async fn get_bulk_batch_with_executor<'e, E>(
        &self,
        executor: E,
        tenant_id: &str,
        instance_id: &str,
        run_id: &str,
        batch_id: &str,
    ) -> Result<Option<WorkflowBulkBatchRecord>>
    where
        E: sqlx::Executor<'e, Database = Postgres>,
    {
        let row = sqlx::query(
            r#"
            SELECT *
            FROM workflow_bulk_batches
            WHERE tenant_id = $1
              AND workflow_instance_id = $2
              AND run_id = $3
              AND batch_id = $4
            "#,
        )
        .bind(tenant_id)
        .bind(instance_id)
        .bind(run_id)
        .bind(batch_id)
        .fetch_optional(executor)
        .await
        .context("failed to load workflow bulk batch")?;
        row.map(Self::decode_bulk_batch_row).transpose()
    }

    async fn get_bulk_chunk_with_executor<'e, E>(
        &self,
        executor: E,
        tenant_id: &str,
        instance_id: &str,
        run_id: &str,
        batch_id: &str,
        chunk_id: &str,
    ) -> Result<Option<WorkflowBulkChunkRecord>>
    where
        E: sqlx::Executor<'e, Database = Postgres>,
    {
        let row = sqlx::query(
            r#"
            SELECT *
            FROM workflow_bulk_chunks
            WHERE tenant_id = $1
              AND workflow_instance_id = $2
              AND run_id = $3
              AND batch_id = $4
              AND chunk_id = $5
            "#,
        )
        .bind(tenant_id)
        .bind(instance_id)
        .bind(run_id)
        .bind(batch_id)
        .bind(chunk_id)
        .fetch_optional(executor)
        .await
        .context("failed to load workflow bulk chunk")?;
        row.map(Self::decode_bulk_chunk_row).transpose()
    }

    async fn enqueue_workflow_event_outbox<'e, E>(
        &self,
        executor: E,
        event: &EventEnvelope<WorkflowEvent>,
        available_at: DateTime<Utc>,
    ) -> Result<()>
    where
        E: sqlx::Executor<'e, Database = Postgres>,
    {
        sqlx::query(
            r#"
            INSERT INTO workflow_event_outbox (
                outbox_id,
                tenant_id,
                workflow_instance_id,
                run_id,
                event_type,
                partition_key,
                event,
                available_at,
                created_at,
                updated_at
            ) VALUES ($1, $2, $3, $4, $5, $6, $7, $8, $8, $8)
            ON CONFLICT (outbox_id) DO NOTHING
            "#,
        )
        .bind(event.event_id)
        .bind(&event.tenant_id)
        .bind(&event.instance_id)
        .bind(&event.run_id)
        .bind(&event.event_type)
        .bind(&event.partition_key)
        .bind(Json(event))
        .bind(available_at)
        .execute(executor)
        .await
        .context("failed to insert workflow event outbox row")?;
        Ok(())
    }

    fn bulk_terminal_event(
        batch: &WorkflowBulkBatchRecord,
        payload: WorkflowEvent,
    ) -> EventEnvelope<WorkflowEvent> {
        let mut envelope = EventEnvelope::new(
            payload.event_type(),
            fabrik_events::WorkflowIdentity::new(
                batch.tenant_id.clone(),
                batch.definition_id.clone(),
                batch.definition_version.unwrap_or_default(),
                batch.artifact_hash.clone().unwrap_or_default(),
                batch.instance_id.clone(),
                batch.run_id.clone(),
                if batch.throughput_backend == "stream-v2" {
                    "throughput-runtime"
                } else {
                    "unified-runtime"
                },
            ),
            payload,
        );
        if let Some(state) = &batch.state {
            envelope.metadata.insert("state".to_owned(), state.clone());
        }
        envelope
    }

    async fn reduce_bulk_batch_reducer_output(
        executor: &mut sqlx::PgConnection,
        batch: &WorkflowBulkBatchRecord,
    ) -> Result<Option<Value>> {
        let reducer = batch.reducer.as_deref();
        if reducer.is_none() {
            return Ok(None);
        }
        if reducer == Some("count") {
            let count = if bulk_reducer_settles(reducer) {
                u64::from(batch.succeeded_items)
                    + u64::from(batch.failed_items)
                    + u64::from(batch.cancelled_items)
            } else {
                u64::from(batch.succeeded_items)
            };
            return Ok(Some(Value::from(count)));
        }

        let mut values = Vec::new();
        let mut errors = Vec::new();
        let rows = sqlx::query(
            r#"
            SELECT output, error, item_count, status
            FROM workflow_bulk_chunks
            WHERE tenant_id = $1
              AND workflow_instance_id = $2
              AND run_id = $3
              AND batch_id = $4
              AND (
                ($5::boolean AND status = 'completed')
                OR ($6::boolean AND status IN ('failed', 'cancelled'))
              )
            ORDER BY chunk_index
            "#,
        )
        .bind(&batch.tenant_id)
        .bind(&batch.instance_id)
        .bind(&batch.run_id)
        .bind(&batch.batch_id)
        .bind(bulk_reducer_requires_success_outputs(reducer))
        .bind(bulk_reducer_requires_error_outputs(reducer))
        .fetch_all(executor)
        .await
        .context("failed to load workflow bulk chunk reducer inputs")?;

        for row in rows {
            let item_count = row
                .try_get::<i32, _>("item_count")
                .context("workflow bulk chunk item_count missing for reducer")?;
            let status = row
                .try_get::<String, _>("status")
                .context("workflow bulk chunk status missing for reducer")?;
            if status == "completed" && bulk_reducer_requires_success_outputs(reducer) {
                if let Some(Json(mut output)) = row
                    .try_get::<Option<Json<Vec<Value>>>, _>("output")
                    .context("workflow bulk chunk output missing for reducer")?
                {
                    values.append(&mut output);
                }
            } else if bulk_reducer_requires_error_outputs(reducer)
                && let Some(error) = row
                    .try_get::<Option<String>, _>("error")
                    .context("workflow bulk chunk error missing for reducer")?
            {
                errors.push((error, item_count.max(0) as u32));
            }
        }
        if bulk_reducer_requires_error_outputs(reducer) {
            return bulk_reducer_reduce_errors(reducer, &errors)
                .context("failed to reduce workflow bulk batch errors");
        }
        if values.is_empty() {
            return Ok(bulk_reducer_default_summary_value(reducer));
        }
        bulk_reducer_reduce_values(reducer, &values)
            .context("failed to reduce workflow bulk batch outputs")
    }

    fn decode_bulk_batch_row(row: sqlx::postgres::PgRow) -> Result<WorkflowBulkBatchRecord> {
        let throughput_backend = row
            .try_get::<String, _>("throughput_backend")
            .context("bulk batch throughput_backend missing")?;
        let execution_policy = row
            .try_get::<Option<String>, _>("execution_policy")
            .context("bulk batch execution_policy missing")?;
        let reducer =
            row.try_get::<Option<String>, _>("reducer").context("bulk batch reducer missing")?;
        let execution_mode = throughput_execution_mode(&throughput_backend).to_owned();
        let derived_routing_reason = throughput_routing_reason(
            &throughput_backend,
            execution_policy.as_deref(),
            reducer.as_deref(),
        )
        .to_owned();
        let routing_reason = row.try_get::<String, _>("routing_reason").unwrap_or_default();
        let reducer_kind = bulk_reducer_name(reducer.as_deref()).to_owned();
        let reducer_version = throughput_reducer_version(reducer.as_deref()).to_owned();
        let reducer_execution_path = throughput_reducer_execution_path(
            &throughput_backend,
            execution_policy.as_deref(),
            reducer.as_deref(),
        )
        .to_owned();
        Ok(WorkflowBulkBatchRecord {
            tenant_id: row.try_get("tenant_id").context("bulk batch tenant_id missing")?,
            instance_id: row
                .try_get("workflow_instance_id")
                .context("bulk batch workflow_instance_id missing")?,
            run_id: row.try_get("run_id").context("bulk batch run_id missing")?,
            definition_id: row.try_get("workflow_id").context("bulk batch workflow_id missing")?,
            definition_version: row
                .try_get::<Option<i32>, _>("workflow_version")
                .context("bulk batch workflow_version missing")?
                .map(|value| value as u32),
            artifact_hash: row
                .try_get("artifact_hash")
                .context("bulk batch artifact_hash missing")?,
            batch_id: row.try_get("batch_id").context("bulk batch batch_id missing")?,
            activity_type: row
                .try_get("activity_type")
                .context("bulk batch activity_type missing")?,
            activity_capabilities: Self::decode_optional_activity_capabilities(
                &row,
                "activity_capabilities",
            )
            .context("bulk batch activity_capabilities missing")?,
            task_queue: row.try_get("task_queue").context("bulk batch task_queue missing")?,
            state: row.try_get("state").context("bulk batch state missing")?,
            input_handle: row
                .try_get::<Json<Value>, _>("input_handle")
                .map(|value| value.0)
                .context("bulk batch input_handle missing")?,
            result_handle: row
                .try_get::<Json<Value>, _>("result_handle")
                .map(|value| value.0)
                .context("bulk batch result_handle missing")?,
            throughput_backend: throughput_backend.clone(),
            throughput_backend_version: row
                .try_get("throughput_backend_version")
                .context("bulk batch throughput_backend_version missing")?,
            execution_mode,
            selected_backend: throughput_backend.clone(),
            routing_reason: if routing_reason.is_empty() {
                derived_routing_reason
            } else {
                routing_reason
            },
            admission_policy_version: row
                .try_get::<String, _>("admission_policy_version")
                .unwrap_or_else(|_| ADMISSION_POLICY_VERSION.to_owned()),
            execution_policy,
            reducer_kind,
            reducer: reducer.clone(),
            reducer_class: row
                .try_get("reducer_class")
                .context("bulk batch reducer_class missing")?,
            reducer_version,
            reducer_execution_path,
            aggregation_tree_depth: row
                .try_get::<i32, _>("aggregation_tree_depth")
                .context("bulk batch aggregation_tree_depth missing")?
                as u32,
            fast_lane_enabled: row
                .try_get("fast_lane_enabled")
                .context("bulk batch fast_lane_enabled missing")?,
            aggregation_group_count: row
                .try_get::<i32, _>("aggregation_group_count")
                .context("bulk batch aggregation_group_count missing")?
                as u32,
            status: WorkflowBulkBatchStatus::from_db(
                &row.try_get::<String, _>("status").context("bulk batch status missing")?,
            )?,
            total_items: row
                .try_get::<i32, _>("total_items")
                .context("bulk batch total_items missing")? as u32,
            chunk_size: row
                .try_get::<i32, _>("chunk_size")
                .context("bulk batch chunk_size missing")? as u32,
            chunk_count: row
                .try_get::<i32, _>("chunk_count")
                .context("bulk batch chunk_count missing")? as u32,
            succeeded_items: row
                .try_get::<i32, _>("succeeded_items")
                .context("bulk batch succeeded_items missing")? as u32,
            failed_items: row
                .try_get::<i32, _>("failed_items")
                .context("bulk batch failed_items missing")? as u32,
            cancelled_items: row
                .try_get::<i32, _>("cancelled_items")
                .context("bulk batch cancelled_items missing")? as u32,
            max_attempts: row
                .try_get::<i32, _>("max_attempts")
                .context("bulk batch max_attempts missing")? as u32,
            retry_delay_ms: row
                .try_get::<i64, _>("retry_delay_ms")
                .context("bulk batch retry_delay_ms missing")? as u64,
            error: row.try_get("error").context("bulk batch error missing")?,
            reducer_output: row
                .try_get::<Option<Json<Value>>, _>("reducer_output")
                .map(|value| value.map(|json| json.0))
                .context("bulk batch reducer_output missing")?,
            scheduled_at: row.try_get("scheduled_at").context("bulk batch scheduled_at missing")?,
            terminal_at: row.try_get("terminal_at").context("bulk batch terminal_at missing")?,
            updated_at: row.try_get("updated_at").context("bulk batch updated_at missing")?,
        })
    }

