    #[tokio::test]
    async fn workflow_task_lease_falls_back_after_expired_sticky_build() -> Result<()> {
        let Some(postgres) = TestPostgres::start()? else {
            return Ok(());
        };
        let store = postgres.connect_store().await?;

        store
            .register_task_queue_build(
                "tenant-a",
                TaskQueueKind::Workflow,
                "payments",
                "build-a",
                &["artifact-a".to_owned()],
                None,
            )
            .await?;
        store
            .register_task_queue_build(
                "tenant-a",
                TaskQueueKind::Workflow,
                "payments",
                "build-b",
                &["artifact-a".to_owned()],
                None,
            )
            .await?;
        store
            .upsert_compatibility_set(
                "tenant-a",
                TaskQueueKind::Workflow,
                "payments",
                "stable",
                &["build-a".to_owned(), "build-b".to_owned()],
                true,
            )
            .await?;

        let event = demo_event("artifact-a");
        let task = store
            .enqueue_workflow_task(2, "payments", Some("build-a"), &event)
            .await?
            .context("workflow task should be created")?;
        let first_lease = store
            .lease_next_workflow_task(2, "poller-a", "build-a", chrono::Duration::milliseconds(1))
            .await?
            .context("preferred build should receive the first lease")?;
        assert_eq!(first_lease.task_id, task.task_id);
        assert_eq!(first_lease.lease_build_id.as_deref(), Some("build-a"));
        assert_eq!(first_lease.lease_poller_id.as_deref(), Some("poller-a"));

        sleep(StdDuration::from_millis(10)).await;

        let fallback_lease = store
            .lease_next_workflow_task(2, "poller-b", "build-b", chrono::Duration::seconds(30))
            .await?
            .context("compatible fallback build should receive the expired lease")?;
        assert_eq!(fallback_lease.task_id, task.task_id);
        assert_eq!(fallback_lease.lease_build_id.as_deref(), Some("build-b"));
        assert_eq!(fallback_lease.lease_poller_id.as_deref(), Some("poller-b"));

        Ok(())
    }

    #[tokio::test]
    async fn workflow_instance_round_trips_compacted_store_state() -> Result<()> {
        let Some(postgres) = TestPostgres::start()? else {
            return Ok(());
        };
        let store = postgres.connect_store().await?;
        let input = json!({"items": [{"value": "x"}, {"value": "y"}]});
        let context = json!([{"value": "x"}, {"value": "y"}]);
        let expected = WorkflowInstanceState {
            tenant_id: "tenant-a".to_owned(),
            instance_id: "wf-store-roundtrip".to_owned(),
            run_id: "run-store-roundtrip".to_owned(),
            definition_id: "demo".to_owned(),
            definition_version: Some(1),
            artifact_hash: Some("artifact-a".to_owned()),
            workflow_task_queue: "default".to_owned(),
            sticky_workflow_build_id: None,
            sticky_workflow_poller_id: None,
            current_state: Some("join".to_owned()),
            context: Some(context.clone()),
            artifact_execution: Some(ArtifactExecutionState {
                bindings: BTreeMap::from([
                    ("input".to_owned(), input.clone()),
                    ("results".to_owned(), json!({"batchId": "batch-1"})),
                ]),
                ..ArtifactExecutionState::default()
            }),
            status: WorkflowStatus::Running,
            input: Some(input.clone()),
            persisted_input_handle: None,
            memo: None,
            search_attributes: None,
            output: None,
            event_count: 1,
            last_event_id: Uuid::now_v7(),
            last_event_type: "WorkflowTriggered".to_owned(),
            updated_at: Utc::now(),
        };

        store.upsert_instance(&expected).await?;

        let persisted: Value = sqlx::query_scalar(
            r#"
            SELECT state
            FROM workflow_instances
            WHERE tenant_id = $1 AND workflow_instance_id = $2
            "#,
        )
        .bind(&expected.tenant_id)
        .bind(&expected.instance_id)
        .fetch_one(&store.pool)
        .await?;
        assert_eq!(persisted.get("input"), Some(&Value::Null));
        assert_eq!(persisted.get("context"), Some(&context));
        assert_eq!(
            persisted
                .get("artifact_execution")
                .and_then(|value| value.get("bindings"))
                .and_then(|value| value.get("input")),
            Some(&input)
        );

        let restored = store
            .get_instance(&expected.tenant_id, &expected.instance_id)
            .await?
            .context("stored workflow instance should exist")?;
        assert_eq!(restored, expected);

        Ok(())
    }

    #[tokio::test]
    async fn workflow_instance_upsert_ignores_stale_snapshot() -> Result<()> {
        let Some(postgres) = TestPostgres::start()? else {
            return Ok(());
        };
        let store = postgres.connect_store().await?;

        let tenant_id = "tenant-a".to_owned();
        let instance_id = "wf-stale-instance".to_owned();
        let run_id = "run-stale-instance".to_owned();
        let base_time = Utc::now();

        let newer = WorkflowInstanceState {
            tenant_id: tenant_id.clone(),
            instance_id: instance_id.clone(),
            run_id: run_id.clone(),
            definition_id: "demo".to_owned(),
            definition_version: Some(1),
            artifact_hash: Some("artifact-a".to_owned()),
            workflow_task_queue: "default".to_owned(),
            sticky_workflow_build_id: None,
            sticky_workflow_poller_id: None,
            current_state: Some("join".to_owned()),
            context: Some(json!({"pending": 0})),
            artifact_execution: Some(ArtifactExecutionState {
                bindings: BTreeMap::from([(
                    "fanout".to_owned(),
                    json!({
                        "origin_state": "dispatch",
                        "wait_state": "join",
                        "pending_count": 0
                    }),
                )]),
                ..ArtifactExecutionState::default()
            }),
            status: WorkflowStatus::Completed,
            input: Some(json!({"items": [1, 2, 3]})),
            persisted_input_handle: None,
            memo: None,
            search_attributes: None,
            output: Some(json!({"ok": true})),
            event_count: 12,
            last_event_id: Uuid::now_v7(),
            last_event_type: "ActivityTaskCompleted".to_owned(),
            updated_at: base_time + chrono::Duration::milliseconds(5),
        };
        let mut stale = newer.clone();
        stale.status = WorkflowStatus::Running;
        stale.context = Some(json!({"pending": 32}));
        stale.output = None;
        stale.event_count = 11;
        stale.last_event_id = Uuid::now_v7();
        stale.updated_at = base_time;

        store.upsert_instance(&newer).await?;
        store.upsert_instance(&stale).await?;

        let restored = store
            .get_instance(&tenant_id, &instance_id)
            .await?
            .context("stored workflow instance should exist")?;
        let mut expected = newer.clone();
        expected.compact_for_persistence();
        expected.expand_after_persistence();
        assert_eq!(restored, expected);

        Ok(())
    }

